select.if:
SELECT t.tablename AS "name", d.description AS "comments" FROM pg_catalog.pg_tables t LEFT JOIN pg_catalog.pg_description d ON (t.tablename::regclass = d.objoid AND d.objsubid = 0) WHERE t.schemaname = current_schema()
AND lower(t.tablename) = lower(#{name})
ORDER BY t.tablename;

SELECT t.column_name AS "name", (CASE WHEN t.is_nullable = 'YES' THEN '1' ELSE '0' END) AS "isNull", (t.ordinal_position * 1) AS "formSort", '1' AS "isEdit", (t.ordinal_position * 10) AS "sort", pgd.description AS "comments", case when character_maximum_length is not null then concat(t.udt_name,'(',character_maximum_length,')') else t.udt_name end AS "jdbcType" FROM information_schema.columns t LEFT JOIN pg_catalog.pg_statio_all_tables st ON t.table_schema = st.schemaname AND t.table_name = st.relname LEFT JOIN pg_catalog.pg_description pgd ON pgd.objoid = st.relid AND pgd.objsubid = t.ordinal_position
WHERE t.table_schema = #{schemaName} AND t.table_name = #{tableName}
WHERE t.table_schema = current_schema() AND t.table_name = #{name}
ORDER BY t.ordinal_position;
